  ('elementary-0a2fc18c-moex-00403', 'elementary-0a2fc18c', 'elementary-0a2fc18c-moex-112-b3f42868', 'sub-elementary-0a2fc18c-01', NULL, 'single_choice', '下列何種情況會使目前國產豬肉需求曲線往左移？', '["人口減少", "豬肉價格下降", "出現狂牛症疑慮", "行政院環境保護署嚴格取締養豬場對環境的污染"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:15+00:00", "source_pdf_sha1": "ea35e40f9519", "answer_pdf_sha1": "d51770cddb1b", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "510", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "經建行政"}'::jsonb, NULL),
  ('elementary-0a2fc18c-moex-00404', 'elementary-0a2fc18c', 'elementary-0a2fc18c-moex-112-b3f42868', 'sub-elementary-0a2fc18c-01', NULL, 'single_choice', '甲、乙兩國均為已開發國家，甲國某年兩性同酬日為2個月又5天，乙國則為2個月又27天，顯示相較 於甲國，乙國受僱員工中女性要花費更多工作時間才能與男性同酬。根據上述，下列何種敘述或推測最 為可能？', '["乙國的性別職業隔離現象較甲國嚴重", "甲國制定的女性勞動政策較乙國友善", "兩國男性受高等教育的比例較女性多", "甲國的受僱者人均國民所得較乙國高"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:15+00:00", "source_pdf_sha1": "ea35e40f9519", "answer_pdf_sha1": "d51770cddb1b", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "510", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "經建行政"}'::jsonb, NULL),
  ('elementary-0a2fc18c-moex-00405', 'elementary-0a2fc18c', 'elementary-0a2fc18c-moex-112-b3f42868', 'sub-elementary-0a2fc18c-01', NULL, 'single_choice', '自強在半導體公司（甲）工作，平日擔任該公司的工會（乙）幹部，回到家裡（丙）是兩個孩子的爸爸， 假日時會帶小孩一起到兒福聯盟（丁）擔任志工，該團體是從事特殊際遇兒童保護工作的非營利組織， 關於前文所述，下列有關甲、乙、丙、丁的分析何者正確？', '["甲屬於《人民團體法》的職業團體", "乙屬於志願結社中的正式團體類型", "丙屬於成員間有職掌與編制的正式團體", "丁屬於私人機構獨立經營的「第二部門」"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:15+00:00", "source_pdf_sha1": "ea35e40f9519", "answer_pdf_sha1": "d51770cddb1b", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "510", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "經建行政"}'::jsonb, NULL),
  ('elementary-0a2fc18c-moex-00406', 'elementary-0a2fc18c', 'elementary-0a2fc18c-moex-112-b3f42868', 'sub-elementary-0a2fc18c-01', NULL, 'single_choice', '我國的《公民投票法》於民國 108 年修正部分條文內容，依據現行規定，下列何項公民投票案可以成為 「全國性公民投票」提案？', '["行政院提出中央政府總預算案", "立法院經司法院核可提出憲法修正案", "總統經行政院院會決議提出所得稅制度改革案", "人民經連署程序提出廢除《電信法》某項條文"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:15+00:00", "source_pdf_sha1": "ea35e40f9519", "answer_pdf_sha1": "d51770cddb1b", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "510", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "經建行政"}'::jsonb, NULL),
  ('elementary-0a2fc18c-moex-00407', 'elementary-0a2fc18c', 'elementary-0a2fc18c-moex-112-b3f42868', 'sub-elementary-0a2fc18c-01', NULL, 'single_choice', '某甲在觀看某部戲劇節目時，發現情節中常會出現某家飲食品牌的標誌，劇中主角的相會地點也通常是 此品牌的店家，使人不知不覺對其產生好感。上述現象最適合用下列何項敘述說明之？', '["媒體藉由廠商品牌以提升節目收視率", "媒體的置入性行銷影響觀眾的認知", "媒體的產製過程受到廣告業主的監督", "閱聽人應加強識讀能力以強化自主判斷"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:15+00:00", "source_pdf_sha1": "ea35e40f9519", "answer_pdf_sha1": "d51770cddb1b", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "510", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "經建行政"}'::jsonb, NULL),
  ('elementary-0a2fc18c-moex-00408', 'elementary-0a2fc18c', 'elementary-0a2fc18c-moex-112-b3f42868', 'sub-elementary-0a2fc18c-01', NULL, 'single_choice', '在最小政府的思潮下，最好的政府是管得最少的政府，下列何者為此思潮強調的政府主要任務？', '["照顧無依民眾", "促進經濟高度成長", "確保基本民生資源供給無虞", "提升生活品質與個人成就機會"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:15+00:00", "source_pdf_sha1": "ea35e40f9519", "answer_pdf_sha1": "d51770cddb1b", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "510", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "經建行政"}'::jsonb, NULL),
  ('elementary-0a2fc18c-moex-00409', 'elementary-0a2fc18c', 'elementary-0a2fc18c-moex-112-b3f42868', 'sub-elementary-0a2fc18c-01', NULL, 'single_choice', '罔市今年70餘歲，她和弟弟命運截然不同，出嫁時父親告訴她不能和弟弟一樣列名族譜，母親說她出嫁 後就不能回去祭祖。父親過世後弟弟要求她主動放棄爸爸的遺產繼承，以我國現行法令來看，若她向法 院或行政主管機關提出救濟，罔市下列主張何者最可能成立？', '["主張罔市這個名字侵害她的姓名權", "不得列名族譜侵害她親權行使權利", "不得回家祭祖限制了她的宗教自由", "弟弟要她放棄遺產侵害她的繼承權"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:15+00:00", "source_pdf_sha1": "ea35e40f9519", "answer_pdf_sha1": "d51770cddb1b", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "510", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "經建行政"}'::jsonb, NULL),
  ('elementary-0a2fc18c-moex-00410', 'elementary-0a2fc18c', 'elementary-0a2fc18c-moex-112-b3f42868', 'sub-elementary-0a2fc18c-01', NULL, 'single_choice', '下列何種法律行為，即使不以書面為之，仍具法律效力？', '["機車租賃", "房屋買賣", "限定繼承", "同性伴侶結婚"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:15+00:00", "source_pdf_sha1": "ea35e40f9519", "answer_pdf_sha1": "d51770cddb1b", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "510", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 12, "answer_corrected": true, "flags": ["answer_corrected_skip_v1"], "civil_slug": "elementary", "civil_category": "經建行政"}'::jsonb, NULL),
  ('elementary-0a2fc18c-moex-00411', 'elementary-0a2fc18c', 'elementary-0a2fc18c-moex-112-b3f42868', 'sub-elementary-0a2fc18c-01', NULL, 'single_choice', '疫情蔓延期間，為避免密閉空間感染風險，民眾搭乘大眾運輸未戴口罩，業者可先進行勸導，如勸導不 聽可拒載，政府並得依《傳染病防治法》向民眾開罰。下列解釋何者正確？', '["民眾未戴口罩，經勸導不聽而被罰，可能會侵害到民眾的社會權", "政府對民眾開罰的依據，須經立法程序，為建構有限政府的條件", "民眾違規被罰，因於疫情蔓延期間，民眾即無申訴及答辯的機會", "政府依法律授權，對違反規定的民眾開罰，稱之為「政治責任」"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:15+00:00", "source_pdf_sha1": "ea35e40f9519", "answer_pdf_sha1": "d51770cddb1b", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "510", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "經建行政"}'::jsonb, NULL),
  ('elementary-0a2fc18c-moex-00412', 'elementary-0a2fc18c', 'elementary-0a2fc18c-moex-112-b3f42868', 'sub-elementary-0a2fc18c-01', NULL, 'single_choice', '我國某直轄市政府為打造友善環境生態，參考民間團體的意見與其他縣市政府的作法，希望透過自治條 例規範非農業用地全面禁止使用除草劑，若查獲違規案件將依規定處罰。前述法規涉及各層級政府權責 及地方治理，下列敘述何者正確？', '["市政府引進第三部門參與政府的公共服務", "屬於地方自治與跨縣市區域經營合辦事項", "屬中央政府委由地方政府代為辦理的事項", "該項法規必須經該直轄市市議會議決通過"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:15+00:00", "source_pdf_sha1": "ea35e40f9519", "answer_pdf_sha1": "d51770cddb1b", "source_family": "moex-gov-tw", "moex": {"exam_code": "112010", "c": "510", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "112", "exam_name": "112年公務人員初等考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "經建行政"}'::jsonb, NULL)
